export * from "./button-group";
export * as ButtonGroup from "./namespace";
export * from "./styles";

"use client";

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import type { VariantProps } from "cva";
import { Group } from "react-aria-components";
import { Separator } from "~/registry/ui/separator";
import { ButtonGroupStyles } from "./styles";

export interface ButtonGroupRootProps
  extends React.ComponentProps<typeof Group>,
    VariantProps<typeof ButtonGroupStyles.Root> {}

export function ButtonGroupRoot({
  className,
  orientation,
  ...props
}: ButtonGroupRootProps) {
  return (
    <Group
      className={ButtonGroupStyles.Root({ orientation, className })}
      data-orientation={orientation}
      data-slot="button-group-root"
      {...props}
    />
  );
}

export interface ButtonGroupTextProps extends useRender.ComponentProps<"div"> {}

export function ButtonGroupText({
  render,
  className,
  ...props
}: ButtonGroupTextProps) {
  const defaultProps: useRender.ElementProps<"div"> = {
    className: ButtonGroupStyles.Text({ className }),
    ["data-slot" as string]: "button-group-text",
  };

  return useRender({
    defaultTagName: "div",
    render,
    props: mergeProps<"div">(defaultProps, props),
  });
}

export interface ButtonGroupSeparatorProps
  extends React.ComponentProps<typeof Separator> {}

export function ButtonGroupSeparator({
  className,
  orientation = "vertical",
  ...props
}: ButtonGroupSeparatorProps) {
  return (
    <Separator
      className={ButtonGroupStyles.Separator({ className })}
      data-slot="button-group-separator"
      orientation={orientation}
      {...props}
    />
  );
}

export {
  ButtonGroupRoot as Root,
  ButtonGroupSeparator as Separator,
  ButtonGroupText as Text,
} from "./button-group";

import { cva } from "~/registry/lib/cva";

export const ButtonGroupStyles = {
  Root: cva({
    base: "flex w-fit items-stretch *:focus-visible:relative *:focus-visible:z-10 has-[>[data-slot=button-group]]:gap-2 has-[select[aria-hidden=true]:last-child]:[&>[data-slot=select-trigger]:last-of-type]:rounded-r-md [&>[data-slot=select-trigger]:not([class*='w-'])]:w-fit [&>input]:flex-1",

    variants: {
      orientation: {
        horizontal:
          "[&>*:not(:first-child)]:rounded-l-none [&>*:not(:first-child)]:border-l-0 [&>*:not(:last-child)]:rounded-r-none",
        vertical:
          "flex-col [&>*:not(:first-child)]:rounded-t-none [&>*:not(:first-child)]:border-t-0 [&>*:not(:last-child)]:rounded-b-none",
      },
    },
    defaultVariants: {
      orientation: "horizontal",
    },
  }),
  Text: cva({
    base: "flex items-center gap-2 rounded-md border bg-muted px-4 font-medium text-sm shadow-xs [&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none",
  }),
  Separator: cva({
    base: "relative m-0! orientation-vertical:h-auto self-stretch bg-input",
  }),
};
